import assert from 'node:assert/strict';
import app from '../index.js';
import { resetStore } from '../models/store.js';
import { resetBuckets, rateLimitDefaults } from './rateLimit.js';

let server, baseUrl;

beforeEach(async () => {
  resetStore();
  resetBuckets();
  server = app.listen(0);
  const port = server.address().port;
  baseUrl = `http://localhost:${port}`;
});

afterEach(() => server.close());

async function createTestUser(overrides = {}) {
  const res = await fetch(`${baseUrl}/api/users`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      name: 'Test User',
      email: `test-${Date.now()}-${Math.random()}@example.com`,
      ...overrides,
    }),
  });
  return res.json();
}

describe('Rate Limiting Middleware', () => {
  describe('response headers on normal requests', () => {
    it('should include X-RateLimit-Limit on GET requests', async () => {
      const res = await fetch(`${baseUrl}/health`);
      assert.equal(res.headers.get('x-ratelimit-limit'), String(rateLimitDefaults.readBucket));
    });

    it('should include X-RateLimit-Remaining on GET requests', async () => {
      const res = await fetch(`${baseUrl}/health`);
      assert.equal(res.headers.get('x-ratelimit-remaining'), String(rateLimitDefaults.readBucket - 1));
    });

    it('should include X-RateLimit-Reset on GET requests', async () => {
      const res = await fetch(`${baseUrl}/health`);
      const reset = res.headers.get('x-ratelimit-reset');
      assert.ok(reset);
      const resetTime = parseInt(reset, 10);
      const now = Math.floor(Date.now() / 1000);
      assert.ok(resetTime >= now, 'Reset time should be in the future or now');
    });

    it('should include rate limit headers on POST requests', async () => {
      const res = await fetch(`${baseUrl}/api/users`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: 'Alice', email: 'alice@example.com' }),
      });
      assert.equal(res.headers.get('x-ratelimit-limit'), String(rateLimitDefaults.writeBucket));
      assert.ok(res.headers.has('x-ratelimit-remaining'));
      assert.ok(res.headers.has('x-ratelimit-reset'));
    });

    it('should decrement remaining on successive requests', async () => {
      const res1 = await fetch(`${baseUrl}/health`);
      const remaining1 = parseInt(res1.headers.get('x-ratelimit-remaining'), 10);

      const res2 = await fetch(`${baseUrl}/health`);
      const remaining2 = parseInt(res2.headers.get('x-ratelimit-remaining'), 10);

      assert.ok(remaining2 < remaining1, 'Remaining should decrease');
    });
  });

  describe('separate read/write buckets', () => {
    it('should use read bucket size for GET requests', async () => {
      const res = await fetch(`${baseUrl}/health`);
      assert.equal(res.headers.get('x-ratelimit-limit'), String(rateLimitDefaults.readBucket));
    });

    it('should use write bucket size for POST requests', async () => {
      const res = await fetch(`${baseUrl}/api/users`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: 'Alice', email: 'alice@example.com' }),
      });
      assert.equal(res.headers.get('x-ratelimit-limit'), String(rateLimitDefaults.writeBucket));
    });

    it('should use write bucket size for PATCH requests', async () => {
      const user = await createTestUser();
      // Create a project to patch
      const projRes = await fetch(`${baseUrl}/api/projects`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: 'P', ownerId: user.id }),
      });
      const project = await projRes.json();

