{"type": "tool_use", "id": "toolu_017AWZjg3otPSFVs6wAX7osf", "name": "Write", "input": {"file_path": "/private/tmp/js-bench-workspace/src/middleware/rateLimit.js", "content": "const READ_METHODS = new Set(['GET', 'HEAD', 'OPTIONS']);

const defaults = {
  readBucket: parseInt(process.env.RATE_LIMIT_READ_BUCKET, 10) || 200,
  readRefill: parseInt(process.env.RATE_LIMIT_READ_REFILL, 10) || 20,
  writeBucket: parseInt(process.env.RATE_LIMIT_WRITE_BUCKET, 10) || 50,
  writeRefill: parseInt(process.env.RATE_LIMIT_WRITE_REFILL, 10) || 5,
};

// Map<ip, { read: { tokens, lastRefill }, write: { tokens, lastRefill } }>
const buckets = new Map();

const CLEANUP_INTERVAL = 60_000;
let cleanupTimer = null;

function startCleanup() {
  if (cleanupTimer) return;
  cleanupTimer = setInterval(() => {
    const now = Date.now();
    for (const [ip, entry] of buckets) {
      const readIdle = now - entry.read.lastRefill > 60_000;
      const writeIdle = now - entry.write.lastRefill > 60_000;
      if (readIdle && writeIdle &&
          entry.read.tokens >= defaults.readBucket &&
          entry.write.tokens >= defaults.writeBucket) {
        buckets.delete(ip);
      }
    }
  }, CLEANUP_INTERVAL);
  cleanupTimer.unref();
}

function getBucket(ip) {
  let entry = buckets.get(ip);
  if (!entry) {
    const now = Date.now();
    entry = {
      read: { tokens: defaults.readBucket, lastRefill: now },
      write: { tokens: defaults.writeBucket, lastRefill: now },
    };
    buckets.set(ip, entry);
    startCleanup();
  }
  return entry;
}

function refill(bucket, maxTokens, refillRate) {
  const now = Date.now();
  const elapsed = (now - bucket.lastRefill) / 1000;
  if (elapsed > 0) {
    bucket.tokens = Math.min(maxTokens, bucket.tokens + elapsed * refillRate);
    bucket.lastRefill = now;
  }
}

export function rateLimiter(req, res, next) {
  const ip = req.ip;
  const entry = getBucket(ip);
  const isRead = READ_METHODS.has(req.method);

  const bucket = isRead ? entry.read : entry.write;
  const maxTokens = isRead ? defaults.readBucket : defaults.writeBucket;
  const refillRate = isRead ? defaults.readRefill : defaults.writeRefill;

  refill(bucket, maxTokens, refillRate);

  const resetSeconds = Math.ceil((maxTokens - bucket.tokens) / refillRate);
  const resetEpoch = Math.floor(Date.now() / 1000) + resetSeconds;

  res.set('X-RateLimit-Limit', String(maxTokens));

  if (bucket.tokens < 1) {
    const retryAfter = Math.ceil((1 - bucket.tokens) / refillRate);
    res.set('X-RateLimit-Remaining', '0');
    res.set('X-RateLimit-Reset', String(resetEpoch));
    res.set('Retry-After', String(retryAfter));
    return res.status(429).json({ error: 'Too many requests' });
  }

  bucket.tokens -= 1;

  res.set('X-RateLimit-Remaining', String(Math.floor(bucket.tokens)));
  res.set('X-RateLimit-Reset', String(resetEpoch));

  next();
}

export function resetBuckets() {
  buckets.clear();
}

